#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 2005;
const int Inf = 0x3f3f3f3f;
struct line{
    int to,wei;//连向什么节点，以及边权是什么
    int Db;//对边的字母首拼，表示对边的 ID 编号是多少
};
int n,k,sum,St,Ed,dis[N];
vector<line> g[N];
queue<int> q;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void Add_edge(int x,int y,int z){
    //用于对两个点之间进行带权双向连边
    //两个点分别是 x 和 y，边权为 z
    int idx=g[x].size(),idy=g[y].size();
    //预先得出这条边对应的两个 ID 编号
    g[x].pb({y,z,idy});//把 x 向 y 的边连上
    g[y].pb({x,0,idx});//把 y 向 x 的边连上，但是这时候边权是 0
    return;//连边环节结束
}
bool BFS_Canit(){//通过 BFS 判断是否图中目前还存在增广边
    for(int i=1;i<=n+k+2;i++)dis[i]=0;//初始化
    while(!q.empty())q.pop();//清空防止残余数据遗留
    dis[St]=1,q.push(St);//设置起点情况，赋初值
    while(!q.empty()){
        int u=q.front();q.pop();
        //取队头并将其弹出，BFS 常规步骤
        for(auto [v,w,id]:g[u])//遍历边
            if(w&&!dis[v]){//如果该边权值为正且没来过
                dis[v]=dis[u]+1;//首先标记情况
                if(v==Ed)return 1;//如果到了终点就直接返回可以
                q.push(v);//否则正常套路塞进队列
            }
    }return 0;//到最后还没找到只好返回不行
}
int DFS_Cntflow(int u,int flow){//求出增广贡献
    if(u==Ed)return flow;//到汇点咯，返回就行
    int now=flow;//记录下增广后的情况，算差值返回
    for(auto &[v,w,id]:g[u])//遍历边
        if(w&&dis[v]==dis[u]+1){//如果该边权值为正且转移路线匹配
            int tmp=DFS_Cntflow(v,min(now,w));//求从 v 出发继续增广的贡献
            if(!tmp)dis[v]=0;//没贡献了就没必要再跑了
            else w-=tmp,g[v][id].wei+=tmp,now-=tmp;//记录贡献情况，改动边权
        }
    return flow-now;//用原先的减去现在的，差值作为返回值
}
int Sol_Dinic(){//求最大流的核心环节，此处采用 Dinic 算法
    int res=0,flow=0;
    while(BFS_Canit())//如果当前还能找到至少一条增广边
        while(flow=DFS_Cntflow(St,Inf))//如果当前的增广边贡献都有效（为正数）
            res+=flow;//那么把贡献累加进答案
    return res;//返回最后得到的最大流答案
}
int main(){
    k=read(),n=read();//读入
    St=n+k+1,Ed=St+1;
    //给两个与正常节点无关的节点编号作为源点和汇点
    for(int i=1;i<=k;i++){
        int w=read();//读入限制量
        sum+=w;//总量统计一下方便后面求 Dinic 之后来判断
        Add_edge(n+i,Ed,w);//在汇点和每个标签之间进行连边
    }
    for(int i=1;i<=n;i++){
        Add_edge(St,i,1);//在源点和每道试题之间进行连边
        int cnt=read();//读入试题 i 的标签个数情况
        while(cnt--){//挨个处理
            int x=read();//把所属标签读进来
            Add_edge(i,x+n,1);//在试题和标签之间进行连边
        }
    }
    if(Sol_Dinic()==sum){
        //如果使用 Dinic 算法找到的最大流大小恰好为 sum
        //说明所找到的最大流就是一种可行的构造方案
        for(int i=1;i<=k;i++){//遍历每种标签
            cout<<i<<":";//按格式输出
            for(auto [j,w,id]:g[n+i])//遍历所有相连的点
                if(w&&j<=n)cout<<" "<<j;//满足要求就输出
            cout<<"\n";//按照题目格式需换行
        }
    }else cout<<"No Solution!\n";
    return 0;
}
